import{_ as e,o as r,c as a,a2 as n}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"🫘 黃豆追蹤日報 — 2026年6月5日（週五）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_20260605.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_20260605.md"}'),l={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_20260605.md"};function o(s,t,i,d,g,c){return r(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="🫘-黃豆追蹤日報-—-2026年6月5日-週五" tabindex="-1">🫘 黃豆追蹤日報 — 2026年6月5日（週五） <a class="header-anchor" href="#🫘-黃豆追蹤日報-—-2026年6月5日-週五" aria-label="Permalink to &quot;🫘 黃豆追蹤日報 — 2026年6月5日（週五）&quot;">​</a></h1><blockquote><p><strong>查詢時間</strong>：TST 05:00 (2026-06-04 21:00 UTC) <strong>資料截止</strong>：2026-06-04（CBOT 黃豆期貨交易日） <strong>⚠️ 注意</strong>：CME 05:00 TST = 17:00 ET（前日），以下包含 6/4 盤中與收盤資訊</p></blockquote><hr><h2 id="🎯-本日敘事錨點" tabindex="-1">🎯 本日敘事錨點 <a class="header-anchor" href="#🎯-本日敘事錨點" aria-label="Permalink to &quot;🎯 本日敘事錨點&quot;">​</a></h2><p><strong>一句話定調</strong>：黃豆跌至約 $11.29（-2.19%），美國天氣有利 + 種植超前 + 油價回落 → 能源/肥料溢價退燒，市場聚焦今晚 USDA 出口銷售是否能止血。</p><hr><h2 id="🎯-持倉風險提示" tabindex="-1">🎯 持倉風險提示 <a class="header-anchor" href="#🎯-持倉風險提示" aria-label="Permalink to &quot;🎯 持倉風險提示&quot;">​</a></h2><p><strong>持倉方向</strong>：⚪ 觀望 <strong>短期風險</strong>：種植超前 + 天氣有利 + 供給預期增加，若出口銷售再弱 → 下行壓力延續 <strong>潛在觸發條件</strong>：USDA 出口銷售大幅低於預期 / 中國加碼採購 / 荷莫茲升級推升肥料與糧運成本 <strong>現價 vs 倉位成本</strong>：無持倉</p><hr><h2 id="📰-重點追蹤-報告主體-—-5-則" tabindex="-1">📰 重點追蹤（報告主體 — 5 則） <a class="header-anchor" href="#📰-重點追蹤-報告主體-—-5-則" aria-label="Permalink to &quot;📰 重點追蹤（報告主體 — 5 則）&quot;">​</a></h2><h3 id="_1️⃣-cbot-黃豆-1-128-75¢-2-19-跌至多月低-供給壓力全面釋放" tabindex="-1">1️⃣ CBOT 黃豆 ~1,128.75¢（-2.19%）：跌至多月低，供給壓力全面釋放 <a class="header-anchor" href="#_1️⃣-cbot-黃豆-1-128-75¢-2-19-跌至多月低-供給壓力全面釋放" aria-label="Permalink to &quot;1️⃣ CBOT 黃豆 ~1,128.75¢（-2.19%）：跌至多月低，供給壓力全面釋放&quot;">​</a></h3><ul><li><strong>6/4 報價</strong>：CBOT 黃豆約 1,128.75 美分/蒲式耳（-2.19%），盤中一度跌至 $11.47½，為 4 月 8 日以來最弱</li><li><strong>7 月合約</strong>：再跌約 31¢，延續 6/3 的 $11.535 跌勢</li><li><strong>驅動因子</strong>： <ul><li>美國中西部降雨改善作物 conditions → 乾旱預期消退</li><li>種植 87% 超前五年均值 80% → 供給時程提前</li><li>油價回落（WTI -3.32%）→ 生物柴油需求溢價退燒</li><li>基金持續減持，技術面偏弱</li></ul></li><li><strong>關鍵位</strong>：下方支撐 $11.00（心理關卡）、上方阻力 $11.53（昨收）</li><li>⏰ TST 05:00 | 來源：<a href="https://tradingeconomics.com/commodity/soybeans" target="_blank" rel="noreferrer">TradingEconomics</a>、<a href="https://www.zawya.com/en/economy/global/corn-and-soybeans-extend-slide-on-favourable-crop-weather-rjy0q1ki" target="_blank" rel="noreferrer">Zawya/Reuters</a></li></ul><h3 id="_2️⃣-usda-出口銷售報告-今晚公布-市場預期偏保守-中國態度是關鍵" tabindex="-1">2️⃣ USDA 出口銷售報告（今晚公布）：市場預期偏保守，中國態度是關鍵 <a class="header-anchor" href="#_2️⃣-usda-出口銷售報告-今晚公布-市場預期偏保守-中國態度是關鍵" aria-label="Permalink to &quot;2️⃣ USDA 出口銷售報告（今晚公布）：市場預期偏保守，中國態度是關鍵&quot;">​</a></h3><ul><li><strong>預估區間</strong>： <ul><li>舊作物淨銷售：100K-500K MT</li><li>新作物（2026/27）淨銷售：60K-300K MT</li></ul></li><li><strong>前次 Flash Sales（6/2）</strong>：合計 24.2M bu（~658K MT），中國買盤回升但仍低於去年同期</li><li><strong>市場解讀</strong>：若出口銷售低於 100K MT → 可能觸發新一波賣壓；若 &gt;400K MT → 短線止跌</li><li><strong>觀察重點</strong>：中國是否持續採購（去關稅化後的需求）+ 新作物訂單是否有實質增量</li><li>⏰ TST 05:00 | 來源：<a href="https://www.farmprogress.com/marketing/flash-sales" target="_blank" rel="noreferrer">FarmProgress</a>、<a href="https://www.barchart.com/futures/quotes/zs*0/futures-prices" target="_blank" rel="noreferrer">Barchart</a></li></ul><h3 id="_3️⃣-usda-作物條件-66-g-e-低於預期-68-小利多但不改供給大方向" tabindex="-1">3️⃣ USDA 作物條件 66% G/E（低於預期 68%）：小利多但不改供給大方向 <a class="header-anchor" href="#_3️⃣-usda-作物條件-66-g-e-低於預期-68-小利多但不改供給大方向" aria-label="Permalink to &quot;3️⃣ USDA 作物條件 66% G/E（低於預期 68%）：小利多但不改供給大方向&quot;">​</a></h3><ul><li><strong>首份 2026 作物條件</strong>：Good-to-Excellent 66%（Reuters 調查預期 68%）</li><li><strong>種植進度</strong>：87%（五年均 80%），出芽 65%（五年均 57%）</li><li><strong>分析</strong>：66% vs 68% 差距極小，市場已反映；真正影響來自「種植超前」+「天氣持續有利」</li><li><strong>後續關注</strong>：6/12 WASDE 將首次更新 2026/27 產量預估</li><li>⏰ TST 05:00 | 來源：<a href="https://www.profarmer.com/pro-farmer-max/evening-report/evening-report-usdas-first-look-corn-and-soybean-conditions" target="_blank" rel="noreferrer">ProFarmer</a>、<a href="https://www.dtnpf.com/agriculture/web/ag/news/article/2026/06/04/periodic-updates-grains-livestock" target="_blank" rel="noreferrer">DTN/Progressive Farmer</a></li></ul><h3 id="_4️⃣-油價回落-→-肥料-能源成本壓力稍緩-但巴西供給壓力持續" tabindex="-1">4️⃣ 油價回落 → 肥料/能源成本壓力稍緩，但巴西供給壓力持續 <a class="header-anchor" href="#_4️⃣-油價回落-→-肥料-能源成本壓力稍緩-但巴西供給壓力持續" aria-label="Permalink to &quot;4️⃣ 油價回落 → 肥料/能源成本壓力稍緩，但巴西供給壓力持續&quot;">​</a></h3><ul><li><strong>WTI $92.83（-3.32%）</strong>：黎以停火壓縮中東風險溢價</li><li><strong>肥料成本傳導</strong>：天然氣 $3.2575（+2.86%），氮肥成本仍在高檔</li><li><strong>巴西出口</strong>：截至 5 月 5,160 萬噸（歷史同期新高），Conab 上調 2026 出口至 1.16 億噸</li><li><strong>連鎖效應</strong>：油價跌 → 生物柴油經濟性下降 → 豆油需求支撐減弱 → 整體黃豆需求承壓</li><li>⏰ TST 05:00 | 來源：<a href="https://gvwire.com/2026/06/04/oil-falls-as-traders-eye-iran-deal-following-lebanon-israel-ceasefire/" target="_blank" rel="noreferrer">Reuters via GVWire</a>、<a href="https://tradingeconomics.com/commodity/natural-gas" target="_blank" rel="noreferrer">TradingEconomics</a>、<a href="https://datamarnews.com/noticias/brazil-breaks-historical-soybean-export-record/" target="_blank" rel="noreferrer">DatamarNews</a></li></ul><h3 id="_5️⃣-聖嬰現象-82-機率-5-7-月-對美豆有利但巴西-2027-有風險" tabindex="-1">5️⃣ 聖嬰現象 82% 機率（5-7 月）：對美豆有利但巴西 2027 有風險 <a class="header-anchor" href="#_5️⃣-聖嬰現象-82-機率-5-7-月-對美豆有利但巴西-2027-有風險" aria-label="Permalink to &quot;5️⃣ 聖嬰現象 82% 機率（5-7 月）：對美豆有利但巴西 2027 有風險&quot;">​</a></h3><ul><li><strong>NOAA/CPC 預測</strong>：2026 年 5-7 月聖嬰機率 82%，8-10 月 98%，可能延續至 2026-27 冬季</li><li><strong>美國中西部</strong>：聖嬰通常帶來涼爽濕潤夏季 → 有利大豆產量（可能 +4%）</li><li><strong>巴西/阿根廷</strong>：過量降雨風險 → 收割延遲</li><li><strong>結構性風險</strong>：聖嬰 + 肥料限制可能影響巴西 2027 作物</li><li>⏰ TST 05:00 | 來源：<a href="https://badgercropnetwork.com/soybean-yield-and-the-2026-super-el-nino-what-growers-need-to-know/" target="_blank" rel="noreferrer">BadgerCropNetwork</a>、<a href="https://en.clickpetroleoegas.com.br/study-reveals-that-el-nino-is-gaining-strength-in-the-pacific-favoring-the-soybean-crop-in-the-united-states-in-2026-and-increasing-the-risk-hl1402/" target="_blank" rel="noreferrer">ClickPetroleoEGas</a></li></ul><hr><h2 id="📈-追蹤速覽" tabindex="-1">📈 追蹤速覽 <a class="header-anchor" href="#📈-追蹤速覽" aria-label="Permalink to &quot;📈 追蹤速覽&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">指標</th><th style="text-align:center;">現值</th><th style="text-align:center;">前值</th><th style="text-align:center;">變化</th><th style="text-align:center;">評估</th></tr></thead><tbody><tr><td style="text-align:left;">CBOT 7月黃豆</td><td style="text-align:center;">~$11.29</td><td style="text-align:center;">$11.535</td><td style="text-align:center;">-2.19%</td><td style="text-align:center;">🔴 多月低點</td></tr><tr><td style="text-align:left;">種植進度</td><td style="text-align:center;">87%</td><td style="text-align:center;">87%</td><td style="text-align:center;">持平</td><td style="text-align:center;">🟡 超前五年均</td></tr><tr><td style="text-align:left;">品質 G-E</td><td style="text-align:center;">66%</td><td style="text-align:center;">-</td><td style="text-align:center;">-</td><td style="text-align:center;">🟡 略低於預期</td></tr><tr><td style="text-align:left;">天然氣</td><td style="text-align:center;">$3.2575</td><td style="text-align:center;">-</td><td style="text-align:center;">+2.86%</td><td style="text-align:center;">🟡 肥料成本壓力</td></tr><tr><td style="text-align:left;">WTI 原油</td><td style="text-align:center;">$92.83</td><td style="text-align:center;">$95.99</td><td style="text-align:center;">-3.32%</td><td style="text-align:center;">🟢 能源成本紓解</td></tr></tbody></table><hr><h2 id="📅-關鍵日期" tabindex="-1">📅 關鍵日期 <a class="header-anchor" href="#📅-關鍵日期" aria-label="Permalink to &quot;📅 關鍵日期&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">日期</th><th style="text-align:left;">事件</th><th style="text-align:center;">重要性</th></tr></thead><tbody><tr><td style="text-align:center;">6/5（週五）</td><td style="text-align:left;"><strong>USDA 出口銷售報告</strong></td><td style="text-align:center;">⭐⭐⭐⭐</td></tr><tr><td style="text-align:center;">6/12（週四）</td><td style="text-align:left;"><strong>USDA WASDE 月報</strong>（首次 2026/27 產量更新）</td><td style="text-align:center;">⭐⭐⭐⭐⭐</td></tr><tr><td style="text-align:center;">6/19（週三）</td><td style="text-align:left;">FOMC 利率決策</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td style="text-align:center;">持續</td><td style="text-align:left;">伊朗/荷莫茲局勢</td><td style="text-align:center;">⭐⭐⭐⭐</td></tr><tr><td style="text-align:center;">持續</td><td style="text-align:left;">美國中西部天氣監測</td><td style="text-align:center;">⭐⭐⭐</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>來源</th><th style="text-align:center;">查詢時間 (TST)</th><th>數據</th></tr></thead><tbody><tr><td>1</td><td><a href="https://tradingeconomics.com/commodity/soybeans" target="_blank" rel="noreferrer">TradingEconomics</a></td><td style="text-align:center;">05:00</td><td>黃豆 ~1,128.75¢</td></tr><tr><td>2</td><td><a href="https://www.zawya.com/en/economy/global/corn-and-soybeans-extend-slide-on-favourable-crop-weather-rjy0q1ki" target="_blank" rel="noreferrer">Zawya/Reuters</a></td><td style="text-align:center;">05:00</td><td>CBOT 跌 2.19%</td></tr><tr><td>3</td><td><a href="https://www.profarmer.com/pro-farmer-max/evening-report/evening-report-usdas-first-look-corn-and-soybean-conditions" target="_blank" rel="noreferrer">ProFarmer</a></td><td style="text-align:center;">05:00</td><td>作物條件 66% G/E</td></tr><tr><td>4</td><td><a href="https://datamarnews.com/noticias/brazil-breaks-historical-soybean-export-record/" target="_blank" rel="noreferrer">DatamarNews</a></td><td style="text-align:center;">05:00</td><td>巴西出口紀錄</td></tr><tr><td>5</td><td><a href="https://badgercropnetwork.com/soybean-yield-and-the-2026-super-el-nino-what-growers-need-to-know/" target="_blank" rel="noreferrer">BadgerCropNetwork</a></td><td style="text-align:center;">05:00</td><td>聖嬰影響分析</td></tr></tbody></table>',29)])])}const y=e(l,[["render",o]]);export{b as __pageData,y as default};
